import CryptoJS from 'crypto-js';
import * as Keychain from 'react-native-keychain';
import { v4 as uuidv4 } from 'uuid';

class EncryptionService {
  constructor() {
    this._encryptionKey = null;
    this._initialized = false;
  }

  async initialize() {
    if (this._initialized) return;

    try {
      const credentials = await Keychain.getGenericPassword({
        service: 'payment_encryption_key',
      });

      if (credentials) {
        this._encryptionKey = credentials.password;
      } else {
        this._encryptionKey = this._generateKey();
        await Keychain.setGenericPassword('payment_key', this._encryptionKey, {
          service: 'payment_encryption_key',
          accessControl: Keychain.ACCESS_CONTROL.BIOMETRY_ANY_OR_DEVICE_PASSCODE,
          accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED_THIS_DEVICE_ONLY,
        });
      }

      this._initialized = true;
    } catch (error) {
      console.error('EncryptionService initialization failed:', error);
      throw new PaymentSecurityError('Failed to initialize encryption service');
    }
  }

  _generateKey() {
    return CryptoJS.lib.WordArray.random(256 / 8).toString();
  }

  encrypt(data) {
    if (!this._initialized) {
      throw new PaymentSecurityError('EncryptionService not initialized');
    }

    const dataString = typeof data === 'string' ? data : JSON.stringify(data);
    const iv = CryptoJS.lib.WordArray.random(128 / 8);
    const encrypted = CryptoJS.AES.encrypt(dataString, this._encryptionKey, {
      iv: iv,
      mode: CryptoJS.mode.CBC,
      padding: CryptoJS.pad.Pkcs7,
    });

    return {
      ciphertext: encrypted.toString(),
      iv: iv.toString(),
      timestamp: Date.now(),
    };
  }

  decrypt(encryptedData) {
    if (!this._initialized) {
      throw new PaymentSecurityError('EncryptionService not initialized');
    }

    try {
      const decrypted = CryptoJS.AES.decrypt(
        encryptedData.ciphertext,
        this._encryptionKey,
        {
          iv: CryptoJS.enc.Hex.parse(encryptedData.iv),
          mode: CryptoJS.mode.CBC,
          padding: CryptoJS.pad.Pkcs7,
        }
      );

      return JSON.parse(decrypted.toString(CryptoJS.enc.Utf8));
    } catch (error) {
      throw new PaymentSecurityError('Decryption failed');
    }
  }

  hashData(data) {
    return CryptoJS.SHA256(JSON.stringify(data)).toString();
  }

  generateTransactionId() {
    return `txn_${uuidv4().replace(/-/g, '')}_${Date.now()}`;
  }

  generateNonce() {
    return CryptoJS.lib.WordArray.random(128 / 8).toString();
  }

  maskCardNumber(cardNumber) {
    if (!cardNumber || cardNumber.length < 4) return '****';
    return `****${cardNumber.slice(-4)}`;
  }

  maskEmail(email) {
    if (!email) return '***';
    const [name, domain] = email.split('@');
    return `${name.charAt(0)}***@${domain}`;
  }

  async storeSecureData(key, data) {
    const encrypted = this.encrypt(data);
    await Keychain.setGenericPassword(key, JSON.stringify(encrypted), {
      service: `payment_secure_${key}`,
      accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED_THIS_DEVICE_ONLY,
    });
  }

  async retrieveSecureData(key) {
    try {
      const credentials = await Keychain.getGenericPassword({
        service: `payment_secure_${key}`,
      });

      if (credentials) {
        const encryptedData = JSON.parse(credentials.password);
        return this.decrypt(encryptedData);
      }
      return null;
    } catch (error) {
      console.error('Failed to retrieve secure data:', error);
      return null;
    }
  }

  async clearSecureData(key) {
    await Keychain.resetGenericPassword({
      service: `payment_secure_${key}`,
    });
  }

  sanitizeInput(input) {
    if (typeof input !== 'string') return input;
    return input.replace(/[<>\"'&]/g, '').trim();
  }

  validateCardNumber(cardNumber) {
    const sanitized = cardNumber.replace(/\s|-/g, '');
    if (!/^\d{13,19}$/.test(sanitized)) return false;

    // Luhn algorithm
    let sum = 0;
    let isEven = false;

    for (let i = sanitized.length - 1; i >= 0; i--) {
      let digit = parseInt(sanitized[i], 10);

      if (isEven) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }

      sum += digit;
      isEven = !isEven;
    }

    return sum % 10 === 0;
  }

  detectCardType(cardNumber) {
    const sanitized = cardNumber.replace(/\s|-/g, '');

    const patterns = {
      visa: /^4/,
      mastercard: /^(5[1-5]|2[2-7])/,
      amex: /^3[47]/,
      discover: /^(6011|65|64[4-9])/,
      diners: /^(30[0-5]|36|38)/,
      jcb: /^35/,
    };

    for (const [type, pattern] of Object.entries(patterns)) {
      if (pattern.test(sanitized)) return type;
    }

    return 'unknown';
  }
}

