import AsyncStorage from '@react-native-async-storage/async-storage';
import encryptionService from './EncryptionService';

class TokenManager {
  constructor() {
    this._tokens = new Map();
    this._tokenRefreshTimers = new Map();
  }

  async storePaymentToken(provider, token, expiresIn = 3600) {
    const tokenData = {
      token,
      provider,
      createdAt: Date.now(),
      expiresAt: Date.now() + expiresIn * 1000,
      nonce: encryptionService.generateNonce(),
    };

    await encryptionService.storeSecureData(`token_${provider}`, tokenData);
    this._tokens.set(provider, tokenData);
    this._scheduleTokenRefresh(provider, expiresIn);

    return tokenData;
  }

  async getPaymentToken(provider) {
    let tokenData = this._tokens.get(provider);

    if (!tokenData) {
      tokenData = await encryptionService.retrieveSecureData(`token_${provider}`);
      if (tokenData) {
        this._tokens.set(provider, tokenData);
      }
    }

    if (tokenData && this._isTokenExpired(tokenData)) {
      await this.removePaymentToken(provider);
      return null;
    }

    return tokenData;
  }

  async removePaymentToken(provider) {
    this._tokens.delete(provider);
    await encryptionService.clearSecureData(`token_${provider}`);

    const timer = this._tokenRefreshTimers.get(provider);
    if (timer) {
      clearTimeout(timer);
      this._tokenRefreshTimers.delete(provider);
    }
  }

  _isTokenExpired(tokenData) {
    const bufferTime = 60 * 1000; // 1 minute buffer
    return Date.now() >= tokenData.expiresAt - bufferTime;
  }

  _scheduleTokenRefresh(provider, expiresIn) {
    const existingTimer = this._tokenRefreshTimers.get(provider);
    if (existingTimer) {
      clearTimeout(existingTimer);
    }

    const refreshTime = (expiresIn - 300) * 1000; // Refresh 5 minutes before expiry
    if (refreshTime > 0) {
      const timer = setTimeout(() => {
        this._onTokenExpiring(provider);
      }, refreshTime);
      this._tokenRefreshTimers.set(provider, timer);
    }
  }

  async _onTokenExpiring(provider) {
    // Emit event for token refresh
    if (this._onRefreshCallback) {
      await this._onRefreshCallback(provider);
    }
  }

  onTokenRefreshNeeded(callback) {
    this._onRefreshCallback = callback;
  }

  async clearAllTokens() {
    for (const [provider] of this._tokens) {
      await this.removePaymentToken(provider);
    }
    this._tokens.clear();
  }
}

export default new TokenManager();

