import axios from 'axios';
import PaymentConfig from '../config/PaymentConfig';
import encryptionService from '../security/EncryptionService';
import tokenManager from '../security/TokenManager';

class PaymentApiClient {
  constructor() {
    this._client = axios.create({
      baseURL: PaymentConfig.apiBaseUrl,
      timeout: PaymentConfig.timeout,
      headers: {
        'Content-Type': 'application/json',
        'X-Platform': Platform.OS,
        'X-App-Version': '1.0.0',
      },
    });

    this._setupInterceptors();
  }

  _setupInterceptors() {
    // Request interceptor
    this._client.interceptors.request.use(
      async (config) => {
        const nonce = encryptionService.generateNonce();
        const timestamp = Date.now().toString();

        config.headers['X-Request-Nonce'] = nonce;
        config.headers['X-Request-Timestamp'] = timestamp;
        config.headers['X-Request-Signature'] = encryptionService.hashData({
          nonce,
          timestamp,
          url: config.url,
          method: config.method,
        });

        // Add auth token if available
        const authToken = await tokenManager.getPaymentToken('auth');
        if (authToken) {
          config.headers['Authorization'] = `Bearer ${authToken.token}`;
        }

        // Encrypt sensitive payload data
        if (config.data && config.data._sensitive) {
          const { _sensitive, ...rest } = config.data;
          config.data = {
            ...rest,
            encryptedPayload: encryptionService.encrypt(_sensitive),
          };
        }

        return config;
      },
      (error) => Promise.reject(error)
    );

    // Response interceptor
    this._client.interceptors.response.use(
      (response) => {
        // Decrypt response if needed
        if (response.data && response.data.encryptedPayload) {
          response.data.decryptedData = encryptionService.decrypt(
            response.data.encryptedPayload
          );
        }
        return response;
      },
      async (error) => {
        if (error.response?.status === 401) {
          // Token expired, attempt refresh
          await this._handleTokenRefresh();
          return this._client.request(error.config);
        }
        return Promise.reject(this._normalizeError(error));
      }
    );
  }

  async _handleTokenRefresh() {
    try {
      const refreshToken = await tokenManager.getPaymentToken('refresh');
      if (refreshToken) {
        const response = await this._client.post('/auth/refresh', {
          refreshToken: refreshToken.token,
        });
        await tokenManager.storePaymentToken('auth', response.data.accessToken);
      }
    } catch (error) {
      await tokenManager.clearAllTokens();
      throw new PaymentApiError('Authentication expired', 'AUTH_EXPIRED');
    }
  }

  _normalizeError(error) {
    if (error.response) {
      return new PaymentApiError(
        error.response.data?.message || 'Payment request failed',
        error.response.data?.code || 'PAYMENT_ERROR',
        error.response.status
      );
    }
    if (error.request) {
      return new PaymentApiError('Network error', 'NETWORK_ERROR');
    }
    return new PaymentApiError(error.message, 'UNKNOWN_ERROR');
  }

  async _retryableRequest(requestFn) {
    const { maxRetries, retryDelay, backoffMultiplier } = PaymentConfig.retryConfig;
    let lastError;

    for (let attempt = 0; attempt <= maxRetries; attempt++) {
      try {
        return await requestFn();
      } catch (error) {
        lastError = error;

        if (
          error.statusCode &&
          error.statusCode < 500 &&
          error.statusCode !== 429
        ) {
          throw error;
        }

        if (attempt < maxRetries) {
          const delay = retryDelay * Math.pow(backoffMultiplier, attempt);
          await new Promise((resolve) => setTimeout(resolve, delay));
        }
      }
    }

    throw lastError;
  }

  // Payment API methods
  async createPaymentIntent(amount, currency, metadata = {}) {
    return this._retryableRequest(() =>
      this._client.post('/payments/intent', {
        amount,
        currency,
        metadata,
        idempotencyKey: encryptionService.generateTransactionId(),
      })
    );
  }

  async confirmPayment(paymentIntentId, paymentMethodData) {
    return this._retryableRequest(() =>
      this._client.post(`/payments/${paymentIntentId}/confirm`, {
        _sensitive: paymentMethodData,
      })
    );
  }

  async verifyReceipt(receipt, platform) {
    return this._retryableRequest(() =>
      this._client.post('/receipts/verify', {
        receipt,
        platform,
        timestamp: Date.now(),
      })
    );
  }

  async getPaymentMethods() {
    return this._retryableRequest(() =>
      this._client.get('/payment-methods')
    );
  }

  async addPaymentMethod(paymentMethodData) {
    return this._retryableRequest(() =>
      this._client.post('/payment-methods', {
        _sensitive: paymentMethodData,
      })
    );
  }

  async removePaymentMethod(paymentMethodId) {
    return this._retryableRequest(() =>
      this._client.delete(`/payment-methods/${paymentMethodId}`)
    );
  }

  async getTransactionHistory(page = 1, limit = 20) {
    return this._retryableRequest(() =>
      this._client.get('/transactions', { params: { page, limit } })
    );
  }

  async requestRefund(transactionId, reason) {
    return this._retryableRequest(() =>
      this._client.post(`/transactions/${transactionId}/refund`, {
        reason,
        idempotencyKey: encryptionService.generateTransactionId(),
      })
    );
  }

  async getSubscriptionStatus() {
    return this._retryableRequest(() =>
      this._client.get('/subscriptions/status')
    );
  }
}

class PaymentApiError extends Error {
  constructor(message, code, statusCode) {
    super(message);
    this.name = 'PaymentApiError';
    this.code = code;
    this.statusCode = statusCode;
  }
}

