// src/services/IAPService.js
import { Platform } from 'react-native';
import {
  initConnection,
  endConnection,
  getProducts,
  getSubscriptions,
  requestPurchase,
  requestSubscription,
  finishTransaction,
  purchaseUpdatedListener,
  purchaseErrorListener,
  getAvailablePurchases,
  acknowledgePurchaseAndroid,
  clearTransactionIOS,
  validateReceiptIos,
  validateReceiptAndroid,
  flushFailedPurchasesCachedAsPendingAndroid,
} from 'react-native-iap';
import PaymentConfig from '../config/PaymentConfig';
import paymentApiClient from '../api/PaymentApiClient';
import encryptionService from '../security/EncryptionService';

class IAPService {
  constructor() {
    this._connected = false;
    this._products = [];
    this._subscriptions = [];
    this._purchaseUpdateSubscription = null;
    this._purchaseErrorSubscription = null;
    this._purchaseListeners = new Set();
    this._errorListeners = new Set();
    this._pendingPurchases = new Map();
  }

  async initialize() {
    try {
      await encryptionService.initialize();
      const result = await initConnection();
      this._connected = true;

      if (Platform.OS === 'android') {
        await flushFailedPurchasesCachedAsPendingAndroid();
      }

      this._setupListeners();
      await this._loadProducts();
      await this._restorePendingPurchases();

      return result;
    } catch (error) {
      console.error('IAP initialization failed:', error);
      throw new IAPError('Failed to initialize in-app purchases', 'INIT_FAILED', error);
    }
  }

  _setupListeners() {
    this._purchaseUpdateSubscription = purchaseUpdatedListener(
      async (purchase) => {
        await this._handlePurchaseUpdate(purchase);
      }
    );

    this._purchaseErrorSubscription = purchaseErrorListener((error) => {
      this._handlePurchaseError(error);
    });
  }

  async _handlePurchaseUpdate(purchase) {
    const transactionId = encryptionService.generateTransactionId();

    try {
      // Validate receipt with backend
      const receipt = Platform.OS === 'ios'
        ? purchase.transactionReceipt
        : purchase.purchaseToken;

      const validation = await paymentApiClient.verifyReceipt(
        receipt,
        Platform.OS
      );

      if (validation.data.valid) {
        // Finish the transaction
        if (Platform.OS === 'ios') {
          await finishTransaction({ purchase, isConsumable: this._isConsumable(purchase.productId) });
        } else if (Platform.OS === 'android') {
          if (!purchase.isAcknowledgedAndroid) {
            await acknowledgePurchaseAndroid({ token: purchase.purchaseToken });
          }
          await finishTransaction({ purchase, isConsumable: this._isConsumable(purchase.productId) });
        }

        const purchaseRecord = {
          transactionId,
          productId: purchase.productId,
          purchaseToken: purchase.purchaseToken,
          transactionReceipt: purchase.transactionReceipt,
          transactionDate: purchase.transactionDate,
          platform: Platform.OS,
          validated: true,
          timestamp: Date.now(),
        };

        // Store purchase record securely
        await encryptionService.storeSecureData(
          `purchase_${transactionId}`,
          purchaseRecord
        );

        // Notify listeners
        this._notifyPurchaseListeners({
          type: 'SUCCESS',
          purchase: purchaseRecord,
        });

        // Resolve pending purchase promise
        const pending = this._pendingPurchases.get(purchase.productId);
        if (pending) {
          pending.resolve(purchaseRecord);
          this._pendingPurchases.delete(purchase.productId);
        }
      } else {
        throw new IAPError('Receipt validation failed', 'VALIDATION_FAILED');
      }
    } catch (error) {
      console.error('Purchase processing failed:', error);

      const pending = this._pendingPurchases.get(purchase.productId);
      if (pending) {
        pending.reject(error);
        this._pendingPurchases.delete(purchase.productId);
      }

      this._notifyErrorListeners({
        type: 'PROCESSING_ERROR',
        error,
        productId: purchase.productId,
      });
    }
  }

  _handlePurchaseError(error) {
    console.error('Purchase error:', error);

    this._notifyErrorListeners({
      type: 'PURCHASE_ERROR',
      error: new IAPError(
        error.message || 'Purchase failed',
        error.code || 'PURCHASE_ERROR',
        error
      ),
    });

    // Reject all pending purchases on error
    for (const [productId, pending] of this._pendingPurchases) {
      pending.reject(new IAPError(error.message, error.code, error));
    }
    this._pendingPurchases.clear();
  }

  async _loadProducts() {
    const platform = Platform.OS;
    const productIds = PaymentConfig.iapProducts[platform] || [];
    const subscriptionIds = PaymentConfig.subscriptionProducts[platform] || [];

    try {
      if (productIds.length > 0) {
        this._products = await getProducts({ skus: productIds });
      }

      if (subscriptionIds.length > 0) {
        this._subscriptions = await getSubscriptions({ skus: subscriptionIds });
      }
    } catch (error) {
      console.error('Failed to load products:', error);
    }
  }

  async _restorePendingPurchases() {
    try {
      const availablePurchases = await getAvailablePurchases();

      for (const purchase of availablePurchases) {
        await this._handlePurchaseUpdate(purchase);
      }
    } catch (error) {
      console.error('Failed to restore pending purchases:', error);
    }
  }

  _isConsumable(productId) {
    const subscriptionIds =
      PaymentConfig.subscriptionProducts[Platform.OS] || [];
    return !subscriptionIds.includes(productId);
  }

  // Public API
  getProducts() {
    return [...this._products];
  }

  getSubscriptions() {
    return [...this._subscriptions];
  }

  getProductById(productId) {
    return (
      this._products.find((p) => p.productId === productId) ||
      this._subscriptions.find((s) => s.productId === productId) ||
      null
    );
  }

  async purchaseProduct(productId) {
    if (!this._connected) {
      throw new IAPError('IAP not initialized', 'NOT_INITIALIZED');
    }

    const product = this.getProductById(productId);
    if (!product) {
      throw new IAPError('Product not found', 'PRODUCT_NOT_FOUND');
    }

    return new Promise((resolve, reject) => {
      this._pendingPurchases.set(productId, { resolve, reject });

      const isSubscription =
        PaymentConfig.subscriptionProducts[Platform.OS]?.includes(productId);

      const purchasePromise = isSubscription
        ? requestSubscription({
            sku: productId,
            ...(Platform.OS === 'android' && {
              subscriptionOffers: [
                {
                  sku: productId,
                  offerToken: product.subscriptionOfferDetails?.[0]?.offerToken,
                },
              ],
            }),
          })
        : requestPurchase({
            sku: productId,
            andDangerouslyFinishTransactionAutomaticallyIOS: false,
          });

      purchasePromise.catch((error) => {
        this._pendingPurchases.delete(productId);
        reject(new IAPError(error.message, error.code, error));
      });
    });
  }

  async restorePurchases() {
    if (!this._connected) {
      throw new IAPError('IAP not initialized', 'NOT_INITIALIZED');
    }

    try {
      const availablePurchases = await getAvailablePurchases();
      const restoredPurchases = [];

      for (const purchase of availablePurchases) {
        const receipt =
          Platform.OS === 'ios'
            ? purchase.transactionReceipt
            : purchase.purchaseToken;

        const validation = await paymentApiClient.verifyReceipt(
          receipt,
          Platform.OS
        );

        if (validation.data.valid) {
          restoredPurchases.push({
            productId: purchase.productId,
            transactionDate: purchase.transactionDate,
            transactionReceipt: purchase.transactionReceipt,
          });
        }
      }

      return restoredPurchases;
    } catch (error) {
      throw new IAPError(
        'Failed to restore purchases',
        'RESTORE_FAILED',
        error
      );
    }
  }

  // Listener management
  addPurchaseListener(listener) {
    this._purchaseListeners.add(listener);
    return () => this._purchaseListeners.delete(listener);
  }

  addErrorListener(listener) {
    this._errorListeners.add(listener);
    return () => this._errorListeners.delete(listener);
  }

  _notifyPurchaseListeners(event) {
    this._purchaseListeners.forEach((listener) => {
      try {
        listener(event);
      } catch (e) {
        console.error('Purchase listener error:', e);
      }
    });
  }

  _notifyErrorListeners(event) {
    this._errorListeners.forEach((listener) => {
      try {
        listener(event);
      } catch (e) {
        console.error('Error listener error:', e);
      }
    });
  }

  async dispose() {
    if (this._purchaseUpdateSubscription) {
      this._purchaseUpdateSubscription.remove();
    }
    if (this._purchaseErrorSubscription) {
      this._purchaseErrorSubscription.remove();
    }

    this._purchaseListeners.clear();
    this._errorListeners.clear();
    this._pendingPurchases.clear();

    if (this._connected) {
      await endConnection();
      this._connected = false;
    }
  }
}

class IAPError extends Error {
  constructor(message, code, originalError) {
    super(message);
    this.name = 'IAPError';
    this.code = code;
    this.originalError = originalError;
  }
}

export { IAPService, IAPError };
export default new IAPService();

