// 7. Digital Wallet Service
// ============================================

// src/services/DigitalWalletService.js
import { Platform } from 'react-native';
import PaymentConfig from '../config/PaymentConfig';
import paymentApiClient from '../api/PaymentApiClient';
import encryptionService from '../security/EncryptionService';

class DigitalWalletService {
  constructor() {
    this._initialized = false;
    this._supportedMethods = [];
  }

  async initialize() {
    await encryptionService.initialize();
    this._supportedMethods = await this._detectSupportedMethods();
    this._initialized = true;
  }

  async _detectSupportedMethods() {
    const methods = [];

    if (Platform.OS === 'ios') {
      methods.push({
        id: PaymentConfig.providers.APPLE_PAY,
        name: 'Apple Pay',
        icon: 'apple-pay',
        available: await this._checkApplePayAvailability(),
      });
    }

    if (Platform.OS === 'android') {
      methods.push({
        id: PaymentConfig.providers.GOOGLE_PAY,
        name: 'Google Pay',
        icon: 'google-pay',
        available: await this._checkGooglePayAvailability(),
      });
    }

    // Always add Stripe and PayPal as options
    methods.push(
      {
        id: PaymentConfig.providers.STRIPE,
        name: 'Credit/Debit Card',
        icon: 'credit-card',
        available: true,
      },
      {
        id: PaymentConfig.providers.PAYPAL,
        name: 'PayPal',
        icon: 'paypal',
        available: true,
      }
    );

    return methods;
  }

  async _checkApplePayAvailability() {
    try {
      // In production, use react-native-payments canMakePayments
      return Platform.OS === 'ios';
    } catch {
      return false;
    }
  }

  async _checkGooglePayAvailability() {
    try {
      // In production, use Google Pay API isReadyToPay
      return Platform.OS === 'android';
    } catch {
      return false;
    }
  }

  getSupportedMethods() {
    return this._supportedMethods.filter((m) => m.available);
  }

  async processApplePayPayment(amount, currency, merchantInfo) {
    if (Platform.OS !== 'ios') {
      throw new WalletError('Apple Pay is only available on iOS', 'PLATFORM_ERROR');
    }

    const paymentRequest = {
      merchantIdentifier: merchantInfo.merchantId,
      supportedNetworks: ['visa', 'mastercard', 'amex'],
      countryCode: 'US',
      currencyCode: currency || PaymentConfig.currency,
      paymentSummaryItems: [
        {
          label: merchantInfo.displayName || 'Payment',
          amount: amount.toString(),
          type: 'final',
        },
      ],
    };

    try {
      // Create payment intent
      const intentResponse = await paymentApiClient.createPaymentIntent(
        amount,
        currency || PaymentConfig.currency,
        { provider: PaymentConfig.providers.APPLE_PAY }
      );

      // Process with Apple Pay (using react-native-payments)
      const paymentResponse = await this._processNativePayment(paymentRequest);

      // Confirm payment with backend
      const confirmation = await paymentApiClient.confirmPayment(
        intentResponse.data.paymentIntentId,
        {
          provider: PaymentConfig.providers.APPLE_PAY,
          paymentData: paymentResponse.details,
          transactionIdentifier: paymentResponse.transactionIdentifier,
        }
      );

      return {
        success: true,
        transactionId: confirmation.data.transactionId,
        amount,
        currency: currency || PaymentConfig.currency,
        provider: PaymentConfig.providers.APPLE_PAY,
        timestamp: Date.now(),
      };
    } catch (error) {
      throw new WalletError(
        error.message || 'Apple Pay payment failed',
        'APPLE_PAY_ERROR',
        error
      );
    }
  }

  async processGooglePayPayment(amount, currency, merchantInfo) {
    if (Platform.OS !== 'android') {
      throw new WalletError(
        'Google Pay is only available on Android',
        'PLATFORM_ERROR'
      );
    }

    const paymentRequest = {
      apiVersion: 2,
      apiVersionMinor: 0,
      allowedPaymentMethods: [
        {
          type: 'CARD',
          parameters: {
            allowedAuthMethods: ['PAN_ONLY', 'CRYPTOGRAM_3DS'],
            allowedCardNetworks: ['VISA', 'MASTERCARD', 'AMEX', 'DISCOVER'],
          },
          tokenizationSpecification: {
            type: 'PAYMENT_GATEWAY',
            parameters: {
              gateway: 'stripe',
              'stripe:publishableKey': merchantInfo.stripePublishableKey,
            },
          },
        },
      ],
      transactionInfo: {
        totalPriceStatus: 'FINAL',
        totalPrice: amount.toString(),
        currencyCode: currency || PaymentConfig.currency,
        countryCode: 'US',
      },
      merchantInfo: {
        merchantId: merchantInfo.merchantId,
        merchantName: merchantInfo.displayName,
      },
    };

    try {
      const intentResponse = await paymentApiClient.createPaymentIntent(
        amount,
        currency || PaymentConfig.currency,
        { provider: PaymentConfig.providers.GOOGLE_PAY }
      );

      const paymentResponse = await this._processNativePayment(paymentRequest);

      const confirmation = await paymentApiClient.confirmPayment(
        intentResponse.data.paymentIntentId,
        {
          provider: PaymentConfig.providers.GOOGLE_PAY,
          paymentData: paymentResponse.paymentMethodData,
        }
      );

      return {
        success: true,
        transactionId: confirmation.data.transactionId,
        amount,
        currency: currency || PaymentConfig.currency,
        provider: PaymentConfig.providers.GOOGLE_PAY,
        timestamp: Date.now(),
      };
    } catch (error) {
      throw new WalletError(
        error.message || 'Google Pay payment failed',
        'GOOGLE_PAY_ERROR',
        error
      );
    }
  }

  async processCardPayment(amount, currency, cardDetails) {
    // Validate card details
    if (!encryptionService.validateCardNumber(cardDetails.cardNumber)) {
      throw new WalletError('Invalid card number', 'INVALID_CARD');
    }

    if (!this._validateExpiry(cardDetails.expiryMonth, cardDetails.expiryYear)) {
      throw new WalletError('Card has expired', 'CARD_EXPIRED');
    }

    if (!this._validateCVV(cardDetails.cvv, cardDetails.cardNumber)) {
      throw new WalletError('Invalid CVV', 'INVALID_CVV');
    }

    try {
      const intentResponse = await paymentApiClient.createPaymentIntent(
        amount,
        currency || PaymentConfig.currency,
        { provider: PaymentConfig.providers.STRIPE }
      );

      const sanitizedCard = {
        cardNumber: encryptionService.sanitizeInput(cardDetails.cardNumber.replace(/\s/g, '')),
        expiryMonth: parseInt(cardDetails.expiryMonth, 10),
        expiryYear: parseInt(cardDetails.expiryYear, 10),
        cvv: encryptionService.sanitizeInput(cardDetails.cvv),
        cardholderName: encryptionService.sanitizeInput(cardDetails.cardholderName || ''),
        billingAddress: cardDetails.billingAddress
          ? {
              line1: encryptionService.sanitizeInput(cardDetails.billingAddress.line1),
              line2: encryptionService.sanitizeInput(cardDetails.billingAddress.line2 || ''),
              city: encryptionService.sanitizeInput(cardDetails.billingAddress.city),
              state: encryptionService.sanitizeInput(cardDetails.billingAddress.state),
              postalCode: encryptionService.sanitizeInput(cardDetails.billingAddress.postalCode),
              country: encryptionService.sanitizeInput(cardDetails.billingAddress.country),
            }
          : undefined,
      };

      const confirmation = await paymentApiClient.confirmPayment(
        intentResponse.data.paymentIntentId,
        {
          provider: PaymentConfig.providers.STRIPE,
          card: sanitizedCard,
        }
      );

      return {
        success: true,
        transactionId: confirmation.data.transactionId,
        amount,
        currency: currency || PaymentConfig.currency,
        provider: PaymentConfig.providers.STRIPE,
        cardType: encryptionService.detectCardType(cardDetails.cardNumber),
        lastFour: encryptionService.maskCardNumber(cardDetails.cardNumber),
        timestamp: Date.now(),
      };
    } catch (error) {
      throw new WalletError(
        error.message || 'Card payment failed',
        'CARD_PAYMENT_ERROR',
        error
      );
    }
  }

  async processPayPalPayment(amount, currency) {
    try {
      const intentResponse = await paymentApiClient.createPaymentIntent(
        amount,
        currency || PaymentConfig.currency,
        { provider: PaymentConfig.providers.PAYPAL }
      );

      // In production, this would open PayPal SDK/web flow
      return {
        paymentIntentId: intentResponse.data.paymentIntentId,
        approvalUrl: intentResponse.data.approvalUrl,
        amount,
        currency: currency || PaymentConfig.currency,
        provider: PaymentConfig.providers.PAYPAL,
      };
    } catch (error) {
      throw new WalletError(
        error.message || 'PayPal payment failed',
        'PAYPAL_ERROR',
        error
      );
    }
  }

  async _processNativePayment(paymentRequest) {
    // Platform-specific native payment processing
    // This is a placeholder - in production, integrate with react-native-payments
    return new Promise((resolve, reject) => {
      // Simulate native payment sheet
      setTimeout(() => {
        resolve({
          details: { paymentData: 'mock_payment_data' },
          transactionIdentifier: encryptionService.generateTransactionId(),
          paymentMethodData: { tokenizationData: { token: 'mock_token' } },
        });
      }, 1000);
    });
  }

  _validateExpiry(month, year) {
    const now = new Date();
    const currentMonth = now.getMonth() + 1;
    const currentYear = now.getFullYear();

    const expMonth = parseInt(month, 10);
    const expYear =
      parseInt(year, 10) < 100
        ? parseInt(year, 10) + 2000
        : parseInt(year, 10);

    if (expMonth < 1 || expMonth > 12) return false;
    if (expYear < currentYear) return false;
    if (expYear === currentYear && expMonth < currentMonth) return false;

    return true;
  }

  _validateCVV(cvv, cardNumber) {
    const cardType = encryptionService.detectCardType(cardNumber);
    const expectedLength = cardType === 'amex' ? 4 : 3;
    return /^\d+$/.test(cvv) && cvv.length === expectedLength;
  }
}

class WalletError extends Error {
  constructor(message, code, originalError) {
    super(message);
    this.name = 'WalletError';
    this.code = code;
    this.originalError = originalError;
  }
}

export { DigitalWalletService, WalletError };
export default new DigitalWalletService();

// ============================================
// 8. Transaction Manager
// ============================================

// src/services/TransactionManager.js
import AsyncStorage from '@react-native-async-storage/async-storage';
import encryptionService from '../security/EncryptionService';
import paymentApiClient from '../api/PaymentApiClient';

const TRANSACTION_STORAGE_KEY = '@payment_transactions';
const MAX_LOCAL_TRANSACTIONS = 100;

class TransactionManager {
  constructor() {
    this._transactions = [];
    this._listeners = new Set();
  }

  async initialize() {
    await this._loadTransactions();
  }

  async _loadTransactions() {
    try {
      const stored = await AsyncStorage.getItem(TRANSACTION_STORAGE_KEY);
      if (stored) {
        const encrypted = JSON.parse(stored);
        this._transactions = encryptionService.decrypt(encrypted);
      }
    } catch (error) {
      console.error('Failed to load transactions:', error);
      this._transactions = [];
    }
  }

  async _saveTransactions() {
    try {
      // Keep only the most recent transactions locally
      const toSave = this._transactions.slice(0, MAX_LOCAL_TRANSACTIONS);
      const encrypted = encryptionService.encrypt(toSave);
      await AsyncStorage.setItem(
        TRANSACTION_STORAGE_KEY,
        JSON.stringify(encrypted)
      );
    } catch (error) {
      console.error('Failed to save transactions:', error);
    }
  }

  async addTransaction(transaction) {
    const record = {
      id: transaction.transactionId || encryptionService.generateTransactionId(),
      productId: transaction.productId,
      amount: transaction.amount,
      currency: transaction.currency,
      provider: transaction.provider,
      status: transaction.status || 'completed',
      type: transaction.type || 'purchase',
      metadata: transaction.metadata || {},
      createdAt: Date.now(),
      hash: encryptionService.hashData(transaction),
    };

    this._transactions.unshift(record);
    await this._saveTransactions();
    this._notifyListeners({ type: 'TRANSACTION_ADDED', transaction: record });

    return record;
  }

  async updateTransactionStatus(transactionId, status) {
    const index = this._transactions.findIndex((t) => t.id === transactionId);
    if (index !== -1) {
      this._transactions[index] = {
        ...this._transactions[index],
        status,
        updatedAt: Date.now(),
      };
      await this._saveTransactions();
      this._notifyListeners({
        type: 'TRANSACTION_UPDATED',
        transaction: this._transactions[index],
      });
    }
  }

  getTransactions(filter = {}) {
    let filtered = [...this._transactions];

    if (filter.status) {
      filtered = filtered.filter((t) => t.status === filter.status);
    }
    if (filter.provider) {
      filtered = filtered.filter((t) => t.provider === filter.provider);
    }
    if (filter.type) {
      filtered = filtered.filter((t) => t.type === filter.type);
    }
    if (filter.startDate) {
      filtered = filtered.filter((t) => t.createdAt >= filter.startDate);
    }
    if (filter.endDate) {
      filtered = filtered.filter((t) => t.createdAt <= filter.endDate);
    }

    return filtered;
  }

  getTransactionById(transactionId) {
    return this._transactions.find((t) => t.id === transactionId) || null;
  }

  async syncWithServer() {
    try {
      const response = await paymentApiClient.getTransactionHistory(1, 50);
      const serverTransactions = response.data.transactions || [];

      // Merge server transactions with local ones
      for (const serverTxn of serverTransactions) {
        const localIndex = this._transactions.findIndex(
          (t) => t.id === serverTxn.id
        );
        if (localIndex === -1) {
          this._transactions.push(serverTxn);
        } else {
          // Server version takes precedence
          this._transactions[localIndex] = {
            ...this._transactions[localIndex],
            ...serverTxn,
          };
        }
      }

      // Sort by date
      this._transactions.sort((a, b) => b.createdAt - a.createdAt);
      await this._saveTransactions();

      return this._transactions;
    } catch (error) {
      console.error('Transaction sync failed:', error);
      throw error;
    }
  }

  async requestRefund(transactionId, reason) {
    const transaction = this.getTransactionById(transactionId);
    if (!transaction) {
      throw new Error('Transaction not found');
    }

    if (transaction.status !== 'completed') {
      throw new Error('Only completed transactions can be refunded');
    }

    try {
      const response = await paymentApiClient.requestRefund(
        transactionId,
        reason
      );
      await this.updateTransactionStatus(transactionId, 'refund_pending');
      return response.data;
    } catch (error) {
      throw error;
    }
  }

  addListener(listener) {
    this._listeners.add(listener);
    return () => this._listeners.delete(listener);
  }

  _notifyListeners(event) {
    this._listeners.forEach((listener) => {
      try {
        listener(event);
      } catch (e) {
        console.error('Transaction listener error:', e);
      }
    });
  }

  async clearLocalTransactions() {
    this._transactions = [];
    await AsyncStorage.removeItem(TRANSACTION_STORAGE_KEY);
  }
}

export default new TransactionManager();

