// 9. React Context & Hooks
// ============================================

// src/context/PaymentContext.js
import React, { createContext, useContext, useReducer, useEffect, useCallback, useRef } from 'react';
import { Platform, Alert } from 'react-native';
import iapService from '../services/IAPService';
import digitalWalletService from '../services/DigitalWalletService';
import transactionManager from '../services/TransactionManager';
import encryptionService from '../security/EncryptionService';

const PaymentContext = createContext(null);

// Action types
const ACTIONS = {
  SET_LOADING: 'SET_LOADING',
  SET_INITIALIZED: 'SET_INITIALIZED',
  SET_PRODUCTS: 'SET_PRODUCTS',
  SET_SUBSCRIPTIONS: 'SET_SUBSCRIPTIONS',
  SET_WALLET_METHODS: 'SET_WALLET_METHODS',
  SET_TRANSACTIONS: 'SET_TRANSACTIONS',
  ADD_TRANSACTION: 'ADD_TRANSACTION',
  SET_PROCESSING: 'SET_PROCESSING',
  SET_ERROR: 'SET_ERROR',
  CLEAR_ERROR: 'CLEAR_ERROR',
  SET_ACTIVE_SUBSCRIPTION: 'SET_ACTIVE_SUBSCRIPTION',
  SET_PAYMENT_METHODS: 'SET_PAYMENT_METHODS',
};

const initialState = {
  initialized: false,
  loading: false,
  processing: false,
  error: null,
  products: [],
  subscriptions: [],
  walletMethods: [],
  transactions: [],
  activeSubscription: null,
  savedPaymentMethods: [],
};

function paymentReducer(state, action) {
  switch (action.type) {
    case ACTIONS.SET_LOADING:
      return { ...state, loading: action.payload };
    case ACTIONS.SET_INITIALIZED:
      return { ...state, initialized: action.payload, loading: false };
    case ACTIONS.SET_PRODUCTS:
      return { ...state, products: action.payload };
    case ACTIONS.SET_SUBSCRIPTIONS:
      return { ...state, subscriptions: action.payload };
    case ACTIONS.SET_WALLET_METHODS:
      return { ...state, walletMethods: action.payload };
    case ACTIONS.SET_TRANSACTIONS:
      return { ...state, transactions: action.payload };
    case ACTIONS.ADD_TRANSACTION:
      return {
        ...state,
        transactions: [action.payload, ...state.transactions],
      };
    case ACTIONS.SET_PROCESSING:
      return { ...state, processing: action.payload };
    case ACTIONS.SET_ERROR:
      return { ...state, error: action.payload, processing: false };
    case ACTIONS.CLEAR_ERROR:
      return { ...state, error: null };
    case ACTIONS.SET_ACTIVE_SUBSCRIPTION:
      return { ...state, activeSubscription: action.payload };
    case ACTIONS.SET_PAYMENT_METHODS:
      return { ...state, savedPaymentMethods: action.payload };
    default:
      return state;
  }
}

export function PaymentProvider({ children, merchantConfig }) {
  const [state, dispatch] = useReducer(paymentReducer, initialState);
  const merchantConfigRef = useRef(merchantConfig);

  useEffect(() => {
    merchantConfigRef.current = merchantConfig;
  }, [merchantConfig]);

  useEffect(() => {
    initializePaymentServices();

    return () => {
      iapService.dispose();
    };
  }, []);

  const initializePaymentServices = async () => {
    dispatch({ type: ACTIONS.SET_LOADING, payload: true });

    try {
      await encryptionService.initialize();
      await iapService.initialize();
      await digitalWalletService.initialize();
      await transactionManager.initialize();

      // Set up IAP listeners
      iapService.addPurchaseListener(handlePurchaseEvent);
      iapService.addErrorListener(handleErrorEvent);

      // Set up transaction listener
      transactionManager.addListener(handleTransactionEvent);

      dispatch({ type: ACTIONS.SET_PRODUCTS, payload: iapService.getProducts() });
      dispatch({
        type: ACTIONS.SET_SUBSCRIPTIONS,
        payload: iapService.getSubscriptions(),
      });
      dispatch({
        type: ACTIONS.SET_WALLET_METHODS,
        payload: digitalWalletService.getSupportedMethods(),
      });
      dispatch({
        type: ACTIONS.SET_TRANSACTIONS,
        payload: transactionManager.getTransactions(),
      });

      dispatch({ type: ACTIONS.SET_INITIALIZED, payload: true });
    } catch (error) {
      console.error('Payment initialization failed:', error);
      dispatch({
        type: ACTIONS.SET_ERROR,
        payload: { message: 'Failed to initialize payment services', code: 'INIT_ERROR' },
      });
      dispatch({ type: ACTIONS.SET_INITIALIZED, payload: true }); // Still mark as initialized
    }
  };

  const handlePurchaseEvent = useCallback(async (event) => {
    if (event.type === 'SUCCESS') {
      const record = await transactionManager.addTransaction({
        ...event.purchase,
        type: 'iap_purchase',
        status: 'completed',
      });
      dispatch({ type: ACTIONS.ADD_TRANSACTION, payload: record });
    }
    dispatch({ type: ACTIONS.SET_PROCESSING, payload: false });
  }, []);

  const handleErrorEvent = useCallback((event) => {
    dispatch({
      type: ACTIONS.SET_ERROR,
      payload: {
        message: event.error?.message || 'Purchase failed',
        code: event.error?.code || 'PURCHASE_ERROR',
      },
    });
    dispatch({ type: ACTIONS.SET_PROCESSING, payload: false });
  }, []);

  const handleTransactionEvent = useCallback((event) => {
    if (event.type === 'TRANSACTION_UPDATED') {
      dispatch({
        type: ACTIONS.SET_TRANSACTIONS,
        payload: transactionManager.getTransactions(),
      });
    }
  }, []);

  // Public methods
  const purchaseProduct = useCallback(async (productId) => {
    dispatch({ type: ACTIONS.CLEAR_ERROR });
    dispatch({ type: ACTIONS.SET_PROCESSING, payload: true });

    try {
      const result = await iapService.purchaseProduct(productId);
      return result;
    } catch (error) {
      dispatch({
        type: ACTIONS.SET_ERROR,
        payload: { message: error.message, code: error.code },
      });
      throw error;
    }
  }, []);

  const processWalletPayment = useCallback(async (provider, amount, currency) => {
    dispatch({ type: ACTIONS.CLEAR_ERROR });
    dispatch({ type: ACTIONS.SET_PROCESSING, payload: true });

    try {
      let result;
      const config = merchantConfigRef.current;

      switch (provider) {
        case 'apple_pay':
          result = await digitalWalletService.processApplePayPayment(
            amount,
            currency,
            config
          );
          break;
        case 'google_pay':
          result = await digitalWalletService.processGooglePayPayment(
            amount,
            currency,
            config
          );
          break;
        case 'stripe':
          throw new Error('Use processCardPayment for card payments');
        case 'paypal':
          result = await digitalWalletService.processPayPalPayment(
            amount,
            currency
          );
          break;
        default:
          throw new Error(`Unsupported payment provider: ${provider}`);
      }

      if (result.success) {
        const record = await transactionManager.addTransaction({
          ...result,
          type: 'wallet_payment',
          status: 'completed',
        });
        dispatch({ type: ACTIONS.ADD_TRANSACTION, payload: record });
      }

      dispatch({ type: ACTIONS.SET_PROCESSING, payload: false });
      return result;
    } catch (error) {
      dispatch({
        type: ACTIONS.SET_ERROR,
        payload: { message: error.message, code: error.code },
      });
      throw error;
    }
  }, []);

  const processCardPayment = useCallback(async (amount, currency, cardDetails) => {
    dispatch({ type: ACTIONS.CLEAR_ERROR });
    dispatch({ type: ACTIONS.SET_PROCESSING, payload: true });

    try {
      const result = await digitalWalletService.processCardPayment(
        amount,
        currency,
        cardDetails
      );

      if (result.success) {
        const record = await transactionManager.addTransaction({
          ...result,
          type: 'card_payment',
          status: 'completed',
        });
        dispatch({ type: ACTIONS.ADD_TRANSACTION, payload: record });
      }

      dispatch({ type: ACTIONS.SET_PROCESSING, payload: false });
      return result;
    } catch (error) {
      dispatch({
        type: ACTIONS.SET_ERROR,
        payload: { message: error.message, code: error.code },
      });
      throw error;
    }
  }, []);

  const restorePurchases = useCallback(async () => {
    dispatch({ type: ACTIONS.SET_LOADING, payload: true });

    try {
      const restored = await iapService.restorePurchases();
      dispatch({ type: ACTIONS.SET_LOADING, payload: false });
      return restored;
    } catch (error) {
      dispatch({ type: ACTIONS.SET_LOADING, payload: false });
      dispatch({
        type: ACTIONS.SET_ERROR,
        payload: { message: error.message, code: error.code },
      });
      throw error;
    }
  }, []);

  const requestRefund = useCallback(async (transactionId, reason) => {
    try {
      return await transactionManager.requestRefund(transactionId, reason);
    } catch (error) {
      dispatch({
        type: ACTIONS.SET_ERROR,
        payload: { message: error.message, code: 'REFUND_ERROR' },
      });
      throw error;
    }
  }, []);

  const clearError = useCallback(() => {
    dispatch({ type: ACTIONS.CLEAR_ERROR });
  }, []);

  const syncTransactions = useCallback(async () => {
    try {
      const synced = await transactionManager.syncWithServer();
      dispatch({ type: ACTIONS.SET_TRANSACTIONS, payload: synced });
    } catch (error) {
      console.error('Sync failed:', error);
    }
  }, []);

  const value = {
    ...state,
    purchaseProduct,
    processWalletPayment,
    processCardPayment,
    restorePurchases,
    requestRefund,
    clearError,
    syncTransactions,
  };

  return (
    <PaymentContext.Provider value={value}>
      {children}
    </PaymentContext.Provider>
  );
}

export function usePayment() {
  const context = useContext(PaymentContext);
  if (!context) {
    throw new Error('usePayment must be used within a PaymentProvider');
  }
  return context;
}

export function useProducts() {
  const { products, subscriptions, loading } = usePayment();
  return { products, subscriptions, loading };
}

export function useTransactions(filter) {
  const { transactions } = usePayment();

  return React.useMemo(() => {
    if (!filter) return transactions;

    return transactions.filter((t) => {
      if (filter.status && t.status !== filter.status) return false;
      if (filter.provider && t.provider !== filter.provider) return false;
      if (filter.type && t.type !== filter.type) return false;
      return true;
    });
  }, [transactions, filter]);
}

export default PaymentContext;

