// src/components/PaymentSheet.js
import React, { useState, useCallback } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  Modal,
  ScrollView,
  ActivityIndicator,
  TextInput,
  KeyboardAvoidingView,
  Platform,
  Alert,
  Image,
} from 'react-native';
import { usePayment } from '../context/PaymentContext';

// ---- Product Card Component ----
export const ProductCard = ({ product, onPurchase, disabled }) => {
  const { processing } = usePayment();

  return (
    <TouchableOpacity
      style={[styles.productCard, disabled && styles.productCardDisabled]}
      onPress={() => onPurchase(product.productId)}
      disabled={disabled || processing}
      activeOpacity={0.7}
    >
      <View style={styles.productInfo}>
        <Text style={styles.productTitle}>{product.title}</Text>
        <Text style={styles.productDescription}>{product.description}</Text>
      </View>
      <View style={styles.productPriceContainer}>
        <Text style={styles.productPrice}>{product.localizedPrice}</Text>
        {processing ? (
          <ActivityIndicator size="small" color="#007AFF" />
        ) : (
          <Text style={styles.purchaseButton}>Buy</Text>
        )}
      </View>
    </TouchableOpacity>
  );
};

// ---- Subscription Card Component ----
export const SubscriptionCard = ({ subscription, isActive, onSubscribe }) => {
  const { processing } = usePayment();

  return (
    <TouchableOpacity
      style={[
        styles.subscriptionCard,
        isActive && styles.subscriptionCardActive,
      ]}
      onPress={() => !isActive && onSubscribe(subscription.productId)}
      disabled={isActive || processing}
      activeOpacity={0.7}
    >
      <View style={styles.subscriptionBadge}>
        <Text style={styles.subscriptionBadgeText}>
          {isActive ? 'Active' : 'Subscribe'}
        </Text>
      </View>
      <Text style={styles.subscriptionTitle}>{subscription.title}</Text>
      <Text style={styles.subscriptionPrice}>
        {subscription.localizedPrice}
        {subscription.subscriptionPeriodAndroid
          ? `/${subscription.subscriptionPeriodAndroid}`
          : '/period'}
      </Text>
      <Text style={styles.subscriptionDescription}>
        {subscription.description}
      </Text>
      {processing && <ActivityIndicator style={styles.loader} />}
    </TouchableOpacity>
  );
};

// ---- Payment Method Selector Component ----
export const PaymentMethodSelector = ({ methods, selectedMethod, onSelect }) => {
  const icons = {
    'apple_pay': '🍎',
    'google_pay': '🔵',
    'stripe': '💳',
    'paypal': '🅿️',
  };

  return (
    <View style={styles.methodSelector}>
      <Text style={styles.methodSelectorTitle}>Payment Method</Text>
      {methods.map((method) => (
        <TouchableOpacity
          key={method.id}
          style={[
            styles.methodOption,
            selectedMethod === method.id && styles.methodOptionSelected,
          ]}
          onPress={() => onSelect(method.id)}
          activeOpacity={0.7}
        >
          <Text style={styles.methodIcon}>{icons[method.id] || '💰'}</Text>
          <Text style={styles.methodName}>{method.name}</Text>
          {selectedMethod === method.id && (
            <Text style={styles.methodCheck}>✓</Text>
          )}
        </TouchableOpacity>
      ))}
    </View>
  );
};

